   326→  bool iterate(const IterateFn<Counter>& fn) const override {
   327→    return store_.counters_.iterate(iterFilter(fn));
   328→  }
   329→  bool iterate(const IterateFn<Gauge>& fn) const override {
   330→    return store_.gauges_.iterate(iterFilter(fn));
   331→  }
   332→  bool iterate(const IterateFn<Histogram>& fn) const override {
   333→    return store_.histograms_.iterate(iterFilter(fn));
   334→  }
   335→  bool iterate(const IterateFn<TextReadout>& fn) const override {
   336→    return store_.text_readouts_.iterate(iterFilter(fn));
   337→  }
   338→
   339→  Counter& counterFromString(const std::string& name) override {
   340→    StatNameManagedStorage storage(name, symbolTable());
   341→    return counterFromStatName(storage.statName());
