   343→  Gauge& gaugeFromString(const std::string& name, Gauge::ImportMode import_mode) override {
   344→    StatNameManagedStorage storage(name, symbolTable());
   345→    return gaugeFromStatName(storage.statName(), import_mode);
   346→  }
   347→  Histogram& histogramFromString(const std::string& name, Histogram::Unit unit) override {
   348→    StatNameManagedStorage storage(name, symbolTable());
   349→    return histogramFromStatName(storage.statName(), unit);
